def solve(*args):
    if not args:
        return None

    # Assuming args should contain metrics as tuples (instance_id, metric_value)
    metrics = []
    for arg in args:
        if isinstance(arg, tuple) and len(arg) == 2:
            instance_id, metric_value = arg
            if isinstance(instance_id, int) and isinstance(metric_value, (int, float)):
                metrics.append((instance_id, metric_value))

    if not metrics:
        return None

    # Aggregate metrics by instance_id
    aggregated_metrics = {}
    for instance_id, metric_value in metrics:
        if instance_id in aggregated_metrics:
            aggregated_metrics[instance_id] += metric_value
        else:
            aggregated_metrics[instance_id] = metric_value

    return aggregated_metrics
